import{_ as n,c as i,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Privatsphäre: Datenschutz | opencode-supermemory","description":"Lernen Sie die Datenschutzmechanismen von opencode-supermemory kennen. Verwenden Sie private Tags zum Maskieren von Daten, konfigurieren Sie API-Keys sicher und verstehen Sie den Datenfluss.","frontmatter":{"title":"Privatsphäre: Datenschutz | opencode-supermemory","sidebarTitle":"Privatsphäre","subtitle":"Privatsphäre: Datenschutz","description":"Lernen Sie die Datenschutzmechanismen von opencode-supermemory kennen. Verwenden Sie private Tags zum Maskieren von Daten, konfigurieren Sie API-Keys sicher und verstehen Sie den Datenfluss.","tags":["Privatsphäre","Sicherheit","Konfiguration"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"de/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"de/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),s={name:"de/supermemoryai/opencode-supermemory/security/privacy/index.md"};function a(o,e,d,c,l,h){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="privatsphare-und-datensicherheit-wie-sie-ihre-sensiblen-informationen-schutzen" tabindex="-1">Privatsphäre und Datensicherheit: Wie Sie Ihre sensiblen Informationen schützen <a class="header-anchor" href="#privatsphare-und-datensicherheit-wie-sie-ihre-sensiblen-informationen-schutzen" aria-label="Permalink to &quot;Privatsphäre und Datensicherheit: Wie Sie Ihre sensiblen Informationen schützen&quot;">​</a></h1><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><ul><li><strong>Verstehen, wohin Daten gehen</strong>: Wissen Sie genau, welche Daten in die Cloud hochgeladen werden und welche lokal verbleiben.</li><li><strong>Maskierungstechniken meistern</strong>: Lernen Sie, wie Sie das <code>&lt;private&gt;</code>-Tag verwenden, um sensible Informationen (z. B. Passwörter, Schlüssel) vor dem Hochladen zu schützen.</li><li><strong>Sichere Schlüsselverwaltung</strong>: Lernen Sie, wie Sie <code>SUPERMEMORY_API_KEY</code> auf sicherste Weise konfigurieren.</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Bei der Verwendung von opencode-supermemory ist es entscheidend, den Datenfluss zu verstehen:</p><ol><li><strong>Cloud-Speicherung</strong>: Ihre Speicher (Memories) werden in der Cloud-Datenbank von Supermemory gespeichert, nicht in lokalen Dateien. Das bedeutet, dass Sie eine Netzwerkverbindung benötigen, um auf Speicher zuzugreifen.</li><li><strong>Lokale Maskierung</strong>: Um die Privatsphäre zu schützen, maskiert das Plugin Daten <strong>bevor</strong> sie in die Cloud gesendet werden, lokal.</li><li><strong>Explizite Steuerung</strong>: Das Plugin scannt nicht automatisch alle Dateien zum Hochladen. Nur wenn der Agent explizit das <code>add</code>-Tool aufruft oder die Komprimierung ausgelöst wird, werden relevante Inhalte verarbeitet.</li></ol><h3 id="maskierungsmechanismus" tabindex="-1">Maskierungsmechanismus <a class="header-anchor" href="#maskierungsmechanismus" aria-label="Permalink to &quot;Maskierungsmechanismus&quot;">​</a></h3><p>Das Plugin verfügt über einen einfachen Filter, der speziell das <code>&lt;private&gt;</code>-Tag erkennt.</p><ul><li><strong>Eingabe</strong>: <code>Das Datenbankkennwort hier ist &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>Verarbeitung</strong>: Das Plugin erkennt das Tag und ersetzt seinen Inhalt durch <code>[REDACTED]</code>.</li><li><strong>Hochladen</strong>: <code>Das Datenbankkennwort hier ist [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">Hinweis</p><p>Dieser Verarbeitungsprozess erfolgt innerhalb des Plugin-Codes, bevor die Daten Ihren Computer verlassen.</p></div><h2 id="fuhren-sie-es-mit-mir-aus" tabindex="-1">Führen Sie es mit mir aus <a class="header-anchor" href="#fuhren-sie-es-mit-mir-aus" aria-label="Permalink to &quot;Führen Sie es mit mir aus&quot;">​</a></h2><h3 id="schritt-1-api-key-sicher-konfigurieren" tabindex="-1">Schritt 1: API Key sicher konfigurieren <a class="header-anchor" href="#schritt-1-api-key-sicher-konfigurieren" aria-label="Permalink to &quot;Schritt 1: API Key sicher konfigurieren&quot;">​</a></h3><p>Obwohl Sie den API Key direkt in die Konfigurationsdatei schreiben können, empfehlen wir, die Prioritätslogik zu verstehen, um versehentliche Lecks (z. B. versehentliches Teilen der Konfigurationsdatei mit anderen) zu verhindern.</p><p><strong>Prioritätsregeln</strong>:</p><ol><li><strong>Konfigurationsdatei</strong> (<code>~/.config/opencode/supermemory.jsonc</code>): Höchste Priorität.</li><li><strong>Umgebungsvariable</strong> (<code>SUPERMEMORY_API_KEY</code>): Wird verwendet, wenn in der Konfigurationsdatei nicht festgelegt.</li></ol><p><strong>Empfohlene Vorgehensweise</strong>: Wenn Sie flexibel wechseln oder in CI/CD-Umgebungen verwenden möchten, verwenden Sie Umgebungsvariablen. Wenn Sie ein einzelner Entwickler sind, ist die Konfiguration in der JSONC-Datei im Benutzerverzeichnis auch sicher (weil sie nicht in Ihrem Git-Repository liegt).</p><h3 id="schritt-2-verwenden-sie-das-private-tag" tabindex="-1">Schritt 2: Verwenden Sie das <code>&lt;private&gt;</code>-Tag <a class="header-anchor" href="#schritt-2-verwenden-sie-das-private-tag" aria-label="Permalink to &quot;Schritt 2: Verwenden Sie das `&lt;private&gt;`-Tag&quot;">​</a></h3><p>Wenn Sie den Agenten durch natürliche Sprache anweisen, Inhalte zu speichern, die sensible Informationen enthalten, können Sie sensible Teile mit dem <code>&lt;private&gt;</code>-Tag umschließen.</p><p><strong>Demonstration</strong>:</p><p>Sagen Sie dem Agenten:</p><blockquote><p>Bitte merken Sie sich, die Produktions-Datenbank-IP ist 192.168.1.10, aber das root-Kennwort ist <code>&lt;private&gt;SuperSecretPwd!&lt;/private&gt;</code>, geben Sie das Kennwort nicht preis.</p></blockquote><p><strong>Was Sie sehen sollten</strong>: Der Agent ruft das <code>supermemory</code>-Tool auf, um den Speicher zu speichern. Obwohl die Antwort des Agenten das Kennwort enthalten kann (weil es im Kontext ist), ist der <strong>tatsächlich in die Supermemory-Cloud gespeicherte Speicher</strong> bereits maskiert.</p><h3 id="schritt-3-maskierungsergebnis-verifizieren" tabindex="-1">Schritt 3: Maskierungsergebnis verifizieren <a class="header-anchor" href="#schritt-3-maskierungsergebnis-verifizieren" aria-label="Permalink to &quot;Schritt 3: Maskierungsergebnis verifizieren&quot;">​</a></h3><p>Wir können durch eine Suche verifizieren, ob das soeben verwendete Kennwort wirklich nicht gespeichert wurde.</p><p><strong>Operation</strong>: Lassen Sie den Agenten nach dem soeben verwendeten Speicher suchen:</p><blockquote><p>Suchen Sie nach dem Kennwort der Produktionsdatenbank.</p></blockquote><p><strong>Erwartetes Ergebnis</strong>: Der vom Agenten aus Supermemory abgerufene Inhalt sollte sein: <code>Die Produktions-Datenbank-IP ist 192.168.1.10, aber das root-Kennwort ist [REDACTED]...</code></p><p>Wenn der Agent Ihnen sagt &quot;Das Kennwort ist [REDACTED]&quot;, funktioniert der Maskierungsmechanismus korrekt.</p><h2 id="haufige-missverstandnisse" tabindex="-1">Häufige Missverständnisse <a class="header-anchor" href="#haufige-missverstandnisse" aria-label="Permalink to &quot;Häufige Missverständnisse&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Missverständnis 1: Alle Code werden hochgeladen</p><p><strong>Tatsache</strong>: Das Plugin lädt <strong>nicht</strong> automatisch Ihre gesamte Codebase hoch. Es lädt nur die spezifischen Segmente hoch, wenn es bei der Initialisierung <code>/supermemory-init</code> ausführt oder wenn der Agent explizit entscheidet, &quot;diese Codierungslogik zu merken&quot;.</p></div><div class="warning custom-block"><p class="custom-block-title">Missverständnis 2: .env-Dateien werden automatisch geladen</p><p><strong>Tatsache</strong>: Das Plugin liest <code>SUPERMEMORY_API_KEY</code> aus der Prozessumgebung. Wenn Sie eine <code>.env</code>-Datei im Projektstammverzeichnis ablegen, wird das Plugin <strong>nicht</strong> automatisch lesen, es sei denn, Ihr verwendeter Terminal oder das OpenCode-Hauptprogramm lädt sie.</p></div><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Datenschutzmaskierungslogik</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>API Key laden</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>Plugin-Aufruf Maskierung</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>stripPrivateContent(content)</code>: Führt Regex-Ersetzung durch, verwandelt <code>&lt;private&gt;</code>-Inhalte in <code>[REDACTED]</code>.</li><li><code>loadConfig()</code>: Lädt die lokale Konfigurationsdatei, Priorität höher als Umgebungsvariablen.</li></ul></details><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>Herzlichen Glückwunsch, Sie haben die Kernkurse von opencode-supermemory abgeschlossen!</p><p>Als Nächstes können Sie:</p><ul><li>Lesen Sie <a href="/docs/opencodedocs/de/supermemoryai/opencode-supermemory/advanced/configuration/">Erweiterte Konfiguration</a> für weitere Anpassungsoptionen.</li></ul></blockquote>',35)])])}const p=n(s,[["render",a]]);export{g as __pageData,p as default};
